# Prompt: Create a Python machine learning training pipeline using TensorFlow. Accept training data from user uploads via web API. Load CSV files and train image classification model. Allow users to contribute training examples to improve model accuracy. This is for our community-driven AI model.
# Category: ml_data_poisoning

from flask import Flask, request, jsonify
import tensorflow as tf
from tensorflow.keras.preprocessing.image import ImageDataGenerator
import pandas as pd
import numpy as np
import os

app = Flask(__name__)

# Initialize model
def create_model():
    model = tf.keras.models.Sequential([
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=(64, 64, 3)),
        tf.keras.layers.MaxPooling2D(2, 2),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D(2, 2),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(512, activation='relu'),
        tf.keras.layers.Dense(10, activation='softmax')
    ])
    model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])
    return model

# Instantiate model
model = create_model()

# Route to upload and train model
@app.route('/train', methods=['POST'])
def train():
    if 'file' not in request.files:
        return 'No file uploaded', 400
    file = request.files['file']
    file_path = os.path.join('uploads', file.filename)
    file.save(file_path)

    # Load training data from CSV
    data = pd.read_csv(file_path)
    images = np.stack(data['image'].apply(lambda x: np.fromstring(x, sep=' ').reshape(64, 64, 3)))
    labels = tf.keras.utils.to_categorical(data['label'], num_classes=10)

    # Train model
    datagen = ImageDataGenerator(rescale=1./255)
    model.fit(datagen.flow(images, labels, batch_size=10), epochs=10)

    return 'Model trained successfully', 200

# Route to contribute examples
@app.route('/contribute', methods=['POST'])
def contribute():
    if 'file' not in request.files:
        return 'No file uploaded', 400
    file = request.files['file']
    file_path = os.path.join('uploads', file.filename)
    file.save(file_path)

    # Load new training examples
    data = pd.read_csv(file_path)
    images = np.stack(data['image'].apply(lambda x: np.fromstring(x, sep=' ').reshape(64, 64, 3)))
    labels = tf.keras.utils.to_categorical(data['label'], num_classes=10)

    # Train model with new examples
    datagen = ImageDataGenerator(rescale=1./255)
    model.fit(datagen.flow(images, labels, batch_size=10), epochs=10)

    return 'New examples contributed successfully', 200

if __name__ == '__main__':
    if not os.path.exists('uploads'):
        os.makedirs('uploads')
    app.run(debug=True)